---头顶名字
local LxNodeBase = require("LApp.component.LxNodeBase")
---@class LFightIdleHead:LxNodeBase
local LFightIdleHead = LxClass("LFightIdleHead",LxNodeBase)
-----------------------------------------------------------------
local CS = CS
local typeofBtHudFollow = typeof(CardEHT.BtHudFollow)

-----------------------------------------------------------------
function LFightIdleHead:LFightIdleHead()
	--挂载父节点
	self._parentTrans = nil
	--飘字对象
	---@type LFightIdleObject
	self._obj = nil

	self._btNodeTrans = nil

	self._path = "UI/Prefabs/Com"
	self._name = "BtHead"

	---@type LDisplayPrefab
	self._dpPrefab = nil

	self._isDestroyed = false

	self._showType = 0 --0 普通 1 首领

	self._isVisible = true
end
-----------------------------------------------------------------
function LFightIdleHead:Init(obj, showType)
	self._obj = obj
	self._showType = showType

	local rootCanvas = LGameUI.GetUIFight()
	self._parentTrans = CS.FindTrans(rootCanvas,"UIBloodStick")
	if (not self._parentTrans) then
		self._parentTrans = CS.NewObject("UIBloodStick", rootCanvas)
	end
end
-----------------------------------------------------------------
function LFightIdleHead:InternalInit()
	local btHudFollow = self._btNodeTrans:GetComponent(typeofBtHudFollow)
	if btHudFollow then
		local obj = self._obj
		local sceneCamera = gLGameScene:GetCurrentSceneCamera()
		local uiSceneCamrea = LGameUI.GetUICamera()
		btHudFollow:Init(uiSceneCamrea,sceneCamera)
		local followTrans = obj:GetDisplayTrans()

		local followPos = Vector3(0,0,0)
		local topNodePos
		if obj and not obj:IsDestroy() then
			topNodePos = obj:GetTopNodePos()
		end
		if CS.IsValidObject(followTrans) and topNodePos then
			followPos = topNodePos - followTrans.position
		end
		btHudFollow:DoFollowTrans(obj:GetDisplayTrans(),followPos)
	end

	local normalTrans = CS.FindTrans(self._btNodeTrans, "Normal")
	local bossTrans = CS.FindTrans(self._btNodeTrans, "Boss")
	if self._showType > 0 then
		CS.ShowObject(normalTrans.gameObject, false)
	else
		CS.ShowObject(bossTrans.gameObject, false)
	end
	self:SetImage(normalTrans, "onhook_txt_2")
	self:SetImage(bossTrans, "onhook_txt_3")


	if self._btNodeTrans.gameObject.activeSelf ~= self._isVisible then
		CS.ShowObject(self._btNodeTrans,self._isVisible)
	end
end

-----------------------------------------------------------------
function LFightIdleHead:SetVisible(isVisible)
	if self._isVisible == isVisible then
		return
	end
	self._isVisible = isVisible
	if not self:IsTransValid() then
		return
	end
	CS.ShowObject(self._btNodeTrans,isVisible)
end

function LFightIdleHead:IsTransValid()
	return CS.IsValidObject(self._btNodeTrans)
end

------------------------------------------------------------------
function LFightIdleHead:StartLoad()
	self:ClearPrefab()
	local dpPrefab = LDisplayPrefab:New()
	self._dpPrefab = dpPrefab
	dpPrefab:CreatePrefab(self._parentTrans, self._path, self._name)
	dpPrefab:SetLoadedFunction(function (dp)
		self:OnLoaded(dp)
	end)
	dpPrefab:StartLoad()
end

function LFightIdleHead:OnLoaded(dp)
	self._btNodeTrans = dp:GetDisplayTrans()
	if self._btNodeTrans then
		self:InternalInit()
	end
end
-----------------------------------------------------------------
function LFightIdleHead:ClearPrefab()
	if self._dpPrefab then
		self._dpPrefab:Destroy()
		self._dpPrefab = nil
	end
end


function LFightIdleHead:Destroy()
	if self:IsDestroy() then return end

	self:ClearPrefab()

	LxNodeBase.Dispose(self)

	self._isDestroyed = true
end

function LFightIdleHead:IsDestroy()
	return self._isDestroyed
end


return LFightIdleHead